// CORE (use-case layer) owns the contract
export interface OrderRepository {
  save(order: Order): Promise<void>;
  findById(id: OrderId): Promise<Order | null>;
}

// CORE depends only on its own interface, never on the DB
export class PlaceOrder {
  constructor(private readonly orders: OrderRepository) {}
  async execute(cmd: PlaceOrderCommand): Promise<OrderId> {
    const order = Order.create(cmd.customerId, cmd.lines);
    await this.orders.save(order);   // calls outward via the port
    return order.id;
  }
}

// OUTER layer implements the inward-defined contract
export class PostgresOrderRepository implements OrderRepository {
  constructor(private readonly pool: Pool) {}
  async save(order: Order): Promise<void> { /* SQL here */ }
  async findById(id: OrderId) { /* SQL here */ return null; }
}

// Output boundary DTO — owned by the use-case layer, framework-free
export interface OrderView {
  id: string;
  status: 'PENDING' | 'CONFIRMED' | 'CANCELLED';
  totalCents: number;
  currency: string;
}

// Adapter maps entity -> DTO. Entity never crosses the boundary.
export function toOrderView(o: Order): OrderView {
  return {
    id: o.id.value,
    status: o.status,
    totalCents: o.total.amountCents,
    currency: o.total.currency,
  };
}

// Use-case layer: port owned by the core, no Stripe types leak in
public interface PaymentGateway {
    RefundResult refund(PaymentId paymentId, Money amount);
}

// Use case enforces the invariant itself - not the SDK, not the controller
public class IssueRefund {
    private final RefundRepository refunds;
    private final PaymentGateway gateway;

    public IssueRefund(RefundRepository refunds, PaymentGateway gateway) {
        this.refunds = refunds;
        this.gateway = gateway;
    }

    public RefundId execute(IssueRefundCommand cmd) {
        Order order = refunds.requireSettledOrder(cmd.orderId());
        Refund refund = order.refund(cmd.amount());      // invariant lives here
        RefundResult res = gateway.refund(order.paymentId(), refund.amount());
        refund.markCompleted(res.providerRef());
        refunds.save(refund);
        return refund.id();
    }
}

// Outer adapter: the ONLY place Stripe types appear
public class StripePaymentGateway implements PaymentGateway {
    private final RefundCreateClient stripe;

    @Override
    public RefundResult refund(PaymentId paymentId, Money amount) {
        RefundCreateParams params = RefundCreateParams.builder()
            .setPaymentIntent(paymentId.value())
            .setAmount(amount.amountInMinorUnits())
            .build();
        com.stripe.model.Refund r = stripe.create(params);
        return new RefundResult(r.getId(), r.getStatus());
    }
}

