module.exports = {
  forbidden: [
    {
      name: 'no-core-to-infra',
      severity: 'error',
      comment: 'Domain/use-cases must not depend on frameworks or adapters',
      from: { path: '^src/(domain|usecases)' },
      to:   { path: '^src/(infrastructure|adapters|frameworks)' },
    },
  ],
};

// Fast use-case test: no DB, no HTTP, no framework
class InMemoryOrders implements OrderRepository {
  private store = new Map<string, Order>();
  async save(o: Order) { this.store.set(o.id.value, o); }
  async findById(id: OrderId) { return this.store.get(id.value) ?? null; }
}

test('PlaceOrder persists a pending order', async () => {
  const repo = new InMemoryOrders();
  const id = await new PlaceOrder(repo).execute({
    customerId: 'c1', lines: [{ sku: 'A', qty: 2 }],
  });
  const saved = await repo.findById(id);
  expect(saved?.status).toBe('PENDING');
});

