// ---------- Entities layer (framework-free) ----------
public final class Product {
    private final ProductId id;
    private final String name;
    private final Money price;

    private Product(ProductId id, String name, Money price) {
        if (price.isNegativeOrZero())
            throw new IllegalArgumentException("price must be positive");
        this.id = id; this.name = name; this.price = price;
    }
    public static Product create(String name, Money price) {
        return new Product(ProductId.newId(), name, price);
    }
    public static Product rehydrate(ProductId id, String name, Money price) {
        return new Product(id, name, price);
    }
    public ProductId id() { return id; }
    public String name() { return name; }
    public Money price() { return price; }
}

// ---------- Use-case layer ----------
public interface ProductRepository {            // PORT, owned by the core
    void save(Product product);
    Optional<Product> findById(ProductId id);
}

public class CreateProduct {
    private final ProductRepository products;
    public CreateProduct(ProductRepository products) { this.products = products; }
    public ProductId execute(CreateProductCommand cmd) {
        Product p = Product.create(cmd.name(), Money.of(cmd.priceCents(), cmd.currency()));
        products.save(p);
        return p.id();
    }
}
public record CreateProductCommand(String name, long priceCents, String currency) {}

// ---------- Interface Adapters: persistence ----------
@Entity @Table(name = "products")
class ProductJpaEntity {
    @Id String id; String name; long priceCents; String currency;
    protected ProductJpaEntity() {}
    ProductJpaEntity(String id, String name, long priceCents, String currency) {
        this.id = id; this.name = name; this.priceCents = priceCents; this.currency = currency;
    }
}
interface ProductJpaRepository extends JpaRepository<ProductJpaEntity, String> {}

@Component
class JpaProductRepository implements ProductRepository {   // implements inward port
    private final ProductJpaRepository jpa;
    JpaProductRepository(ProductJpaRepository jpa) { this.jpa = jpa; }
    public void save(Product p) {
        jpa.save(new ProductJpaEntity(p.id().value(), p.name(),
                 p.price().amountCents(), p.price().currency()));
    }
    public Optional<Product> findById(ProductId id) {
        return jpa.findById(id.value()).map(e ->
            Product.rehydrate(new ProductId(e.id), e.name, Money.of(e.priceCents, e.currency)));
    }
}

// ---------- Interface Adapters: web ----------
@RestController
@RequestMapping("/products")
class ProductController {
    private final CreateProduct createProduct;
    ProductController(CreateProduct createProduct) { this.createProduct = createProduct; }

    @PostMapping
    ResponseEntity<ProductResponse> create(@RequestBody @Valid CreateProductRequest req) {
        ProductId id = createProduct.execute(
            new CreateProductCommand(req.name(), req.priceCents(), req.currency()));
        return ResponseEntity.status(201).body(new ProductResponse(id.value()));
    }
}
record CreateProductRequest(@NotBlank String name, @Positive long priceCents, String currency) {}
record ProductResponse(String id) {}

// ---------- Frameworks & Drivers ----------
@Configuration
class UseCaseConfig {
    @Bean CreateProduct createProduct(ProductRepository repo) { return new CreateProduct(repo); }
}

// ---------- Use-case layer: the port (framework-free) ----------
export interface SmsSender {
  send(to: string, body: string): Promise<void>;
}

export interface CustomerLookup {
  phoneFor(customerId: string): Promise<string | null>;
}

export class NotifyCustomer {
  constructor(
    private readonly customers: CustomerLookup,
    private readonly sms: SmsSender,
  ) {}

  async execute(customerId: string, message: string): Promise<void> {
    const phone = await this.customers.phoneFor(customerId);
    if (!phone) throw new Error(`no phone for customer ${customerId}`);
    if (message.trim().length === 0) throw new Error('message must not be empty');
    await this.sms.send(phone, message);
  }
}

// ---------- Adapter: the ONLY place Twilio appears ----------
import twilio from 'twilio';

export class TwilioSmsSender implements SmsSender {
  private readonly client = twilio(process.env.TWILIO_SID!, process.env.TWILIO_TOKEN!);
  constructor(private readonly from: string) {}
  async send(to: string, body: string): Promise<void> {
    await this.client.messages.create({ to, from: this.from, body });
  }
}

// ---------- Fast unit test: no network, no SDK ----------
class FakeSmsSender implements SmsSender {
  public sent: Array<{ to: string; body: string }> = [];
  async send(to: string, body: string) { this.sent.push({ to, body }); }
}
class StubCustomers implements CustomerLookup {
  async phoneFor(id: string) { return id === 'c1' ? '+15550001111' : null; }
}

test('NotifyCustomer sends an SMS to the customer phone', async () => {
  const sms = new FakeSmsSender();
  const useCase = new NotifyCustomer(new StubCustomers(), sms);
  await useCase.execute('c1', 'Your order shipped');
  expect(sms.sent).toEqual([{ to: '+15550001111', body: 'Your order shipped' }]);
});

test('NotifyCustomer rejects an unknown customer', async () => {
  const useCase = new NotifyCustomer(new StubCustomers(), new FakeSmsSender());
  await expect(useCase.execute('nope', 'hi')).rejects.toThrow(/no phone/);
});
